import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.encoder.Encode;

public class XSSSecureCode {
    public void displayMessage(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("message");
        String safeInput = Encode.forHtml(userInput); // Sanitize and encode user input

        String htmlResponse = "<html><body><h1>" + safeInput + "</h1></body></html>";

        response.getWriter().write(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
